"""Lucide-derived SVG icons rendered to QIcon at runtime.

Each entry is the full inline <svg ...> markup with stroke="currentColor"
so we can swap the colour per-call (e.g. for a light/dark theme switch)
without shipping multiple raster sets.

Usage
-----
    from petrilya.ui.icons import icon
    btn.setIcon(icon("folder-open"))
    btn.setIcon(icon("play", size=20, color="#1a1304"))
"""

from __future__ import annotations

from PySide6.QtCore import QByteArray, Qt
from PySide6.QtGui import QIcon, QPainter, QPixmap
from PySide6.QtSvg import QSvgRenderer


